#include <stdio.h>

int main() {
    double a, b, result;
    char op;
    printf("Enter: number op number  (e.g. 5 + 3): ");
    scanf("%lf %c %lf", &a, &op, &b);
    if (op == '+') result = a + b;
    else if (op == '-') result = a - b;
    else if (op == '*') result = a * b;
    else if (op == '/') result = a / b;
    else { printf("Bad op\n"); return 1; }
    printf("%.2f %c %.2f = %.2f\n", a, op, b, result);
    return 0;
}
